import React from 'react'
import arrow from '../../../../img/icons/arrow.svg'

export default function Services() {

   const servicesList = [
      {
         title: 'Graphic Design',
         list: [
            'Whitepapers / Documents',
            'Pitchdecks',
            'Social Media Posts',
            'Brochures / Magazines',
            'Product Mockups',
            'Advertisements',
            'Product Packaging / Invitations',
            'Banners',
         ]
      },
      {
         title: 'Branding',
         list: [
            'Logo Design',
            'Corporate Identity',
            'Branding / Brandbooks',
            'Brand Guidelines',
            'Business Cards',
            'Merchandise',
            'Typography',
         ]
      },
      {
         title: 'Webdesign',
         list: [
            'Website UI',
            'Mobile Applications',
            'Design Systems',
            'Wireframes',
         ]
      },
      {
         title: 'Animation',
         list: [
            '2D Animation',
            '3D Animation',
            'Product Videos',
            'Promotion Videos',
         ]
      },
      {
         title: '3D Design',
         list: [
            'NFT Design',
            'Logo Animation',
            'Graphics Support',
            '3D Modelling',
         ]
      },
      {
         title: 'Video Editing',
         list: [
            'Video Editing',
            'Mobile Applications',
            'Story Boards',
         ]
      },
   ]

  return (
    <section id='Services' className='hone__services services'>
      <div className="services__container">
      <div className="services__section-block section-block">
            <div className="section-block__head">
               <h2 className="section-title">Services</h2>
               <button className="button services__button">
                  <div className="button__text">Explore</div>
                  <i className="button__icon">
                     <img src={arrow} alt="icon" />
                  </i>
               </button>
            </div>
            <div className="section-block__body">
               {
                  servicesList.map((item,i)=>{
                     return <div key={i} className='services__row'>
                        <div className="services__column services__titles">
                           <div className="title-sub-2">{item.title}</div>
                        </div>
                        <div className="services__column services__labels">
                           <ul className='services__list'>
                              {
                                 item.list.map((item,i)=>{
                                    return <li key={i} className='services__item label'>{item}</li>
                                 })
                              }
                              
                           </ul>
                        </div>
                     </div>
                  })
               }
            </div>
            
            <button className="button section-block__button">
               <div className="button__text">Book a Call</div>
            </button>
         </div>
      </div>
    </section>
  )
}
