import React, { useEffect } from 'react'
import arrow from '../../../../img/icons/arrow.svg'
import asidepic1 from '../../../../img/casestudio/casestudio1-1.webp'

import mainPicture1 from '../../../../img/casestudio/casestudio1.webp'
import mainPicture2 from '../../../../img/usecases/trenfinance/head.webp'
import mainPicture3 from '../../../../img/usecases/venom/cover.webp'
import mainPicture4 from '../../../../img/usecases/zume/head.webp'

import { HiArrowLongRight } from "react-icons/hi2";
import { Link } from 'react-router-dom';
import { Swiper, SwiperSlide } from 'swiper/react';
import { Mousewheel } from 'swiper/modules';


export default function Casestudies(props) {
   
   const casestudioList = [
      {
         mainPicture: mainPicture2,
         title: 'TrenFinance',
         list: ['UI/UX','Social media posts'],
         link: 'trenfinance',
         asideText: 'We can have a small description here about the project and maybe something related the project that will make people click the view button',
         asidePicture: asidepic1,
      },
      {
         mainPicture: mainPicture1,
         title: 'Hetrix',
         list: ['UI/UX','Social media posts'],
         link: 'hetrix',
         asideText: 'We can have a small description here about the project and maybe something related the project that will make people click the view button',
         asidePicture: asidepic1,
      },
      {
         mainPicture: mainPicture3,
         title: 'Venom Foundation',
         list: ['UI/UX','Social media posts'],
         link: 'venom',
         asideText: 'We can have a small description here about the project and maybe something related the project that will make people click the view button',
         asidePicture: asidepic1,
      },      {
         mainPicture: mainPicture4,
         title: 'Zume',
         list: ['UI/UX','Social media posts'],
         link: 'zume',
         asideText: 'We can have a small description here about the project and maybe something related the project that will make people click the view button',
         asidePicture: asidepic1,
      },
      
   ]

  return (
    <section id='Work' className='home__casestudies casestudies'>
      <div className="casestudies__container">
      <div className="casestudies__section-block section-block">
            <div className="section-block__head">
               <h2 className="section-title">Case Studies</h2>
               <button className="button casestudies__button">
                  <div className="button__text">Book a Call</div>
                  <i className="button__icon">
                     <img src={arrow} alt="icon" />
                  </i>
               </button>
            </div>
            <div className="section-block__body" style={{height: window.innerWidth > 991 ? casestudioList.length * 930 / 2+'px' : ''}}>
               <Swiper
               modules={[Mousewheel]}
               // allowTouchMove={false}
               speed={500}
               // loop={true}
               className="mySwiper"
                  direction={'vertical'}
                  slidesPerView={1}
                  // spaceBetween={30}
                  mousewheel={true}
               >
               {
                  casestudioList.map((item,i)=>{
                     return <SwiperSlide key={i}> <div  className='casestudies__row'>
                     <div className="casestudies__content">
                         <Link to={item.link} className="casestudies__picture -ibg" onMouseEnter={()=> {props.sishvr(true)}} onClick={()=>{
                           props.sishvr(false)
                           
                           }} onMouseLeave={()=>{props.sishvr(false)}}>
                            <img src={item.mainPicture} alt="picture" />
                         </Link>
                        <div className="casestudies__body casestudies-body">
                           <div className="casestudies-body__title">{item.title}</div>
                           <div className="casestudies-body__labels">
                              {
                                 item.list.map((item,i)=>{
                                    return <div key={i} className="casestudies-body__label label">{item}</div>
                                 })
                              }
                           </div>
                           <Link to={item.link} className='link'>
                              <span className="link__text">View work</span>
                              <HiArrowLongRight />
                           </Link>
                        </div>
                     </div>
                     <div className="casestudies__aside casestudies-aside">
                        <div className="casestudies-aside__text">{item.asideText}</div>
                        <div className="casestudies-aside__picture -ibg">
                           <img src={item.asidePicture} alt="picture" />
                        </div>
                     </div>
                  </div>
                  </SwiperSlide>
                  })
               }
              </Swiper>
              {
                  casestudioList.map((item,i)=>{
                     return <div key={i}> <div  className='casestudies__row md2'>
                     <div className="casestudies__content">
                         <Link to={item.link} className="casestudies__picture -ibg" onMouseEnter={()=> {props.sishvr(true)}} onClick={()=>{
                           props.sishvr(false)
                           
                           }} onMouseLeave={()=>{props.sishvr(false)}}>
                            <img src={item.mainPicture} alt="picture" />
                         </Link>
                        <div className="casestudies__body casestudies-body">
                           <div className="casestudies-body__title">{item.title}</div>
                           <div className="casestudies-body__labels">
                              {
                                 item.list.map((item,i)=>{
                                    return <div key={i} className="casestudies-body__label label">{item}</div>
                                 })
                              }
                           </div>
                           <Link to={item.link} className='link'>
                              <span className="link__text">View work</span>
                              <HiArrowLongRight />
                           </Link>
                        </div>
                     </div>
                     <div className="casestudies__aside casestudies-aside">
                        <div className="casestudies-aside__text">{item.asideText}</div>
                        <div className="casestudies-aside__picture -ibg">
                           <img src={item.asidePicture} alt="picture" />
                        </div>
                     </div>
                  </div>
                  </div>
                  })
               }
            </div>
         
         </div>
      </div>
    </section>
  )
}
