import React from 'react'
import videoLink from '../../../../videos/Project.mp4'
import { Link } from 'react-router-dom'
import Letstalk from '../../../General/Letstalk'
// onMouseEnter={()=> {props.setIsHovered(true)}} onMouseLeave={()=>{props.setIsHovered(false)}}
export default function Head(props) {
  return (
    <section className='home__head head'>
      <div className="head__video" dangerouslySetInnerHTML={{ __html: `
        <video
          loop
          muted
          autoplay
          playsInline
          src="${videoLink}"
        ></video>
      ` }}></div>
      <div className="head__content">
         <h1 className="head__title">Designing the future for <mark>Startups</mark></h1>
         <p className="head__text">The strategic design partner for businesses wanting to scale to higher levels. Check out our convenient <mark>plans</mark>.</p>
         <Letstalk />
      </div>
    </section>
  )
}
