import React, { useState } from 'react'
import { Link } from 'react-router-dom'
import { IoMdArrowForward } from "react-icons/io";
import WordShuffler from './WordShuffler';

export default function Letstalk() {

   const [ripplePosition, setRipplePosition] = useState({ x: 0, y: 0 });
   const [buttonActive, setButtonActive] = useState(false);
 
   const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
   const [randomPositions, setRandomPositions] = useState([]);

   const [shuffling, setShuffling] = useState(false);

   const handleMouseMove = (e) => {
      if(window.innerWidth > 991) {
         setMousePosition({ x: e.clientX, y: e.clientY });
      }
    };
  const getRandomPosition = () => Math.floor(Math.random() * 2000); // Adjust the maximum value as needed

   const handleHover = (e) => {
      if(window.innerWidth > 991) {
     const rect = e.target.getBoundingClientRect();
     const x = e.clientX - rect.left;
     const y = e.clientY - rect.top;
     setRipplePosition({ x, y });
     setButtonActive(true);
      //   ----------------------------
      // Generate random initial positions for the parallax items when the button is hovered
      const positions = Array.from({ length: 100 }, () => ({
        left: getRandomPosition(),
        top: getRandomPosition(),
      }));
      setRandomPositions(positions);
      setShuffling(!shuffling);
   }
};
   const handleButtonLeave = () => {
      setButtonActive(false);
    };


  return (
    <section className='home__letstalk letstalk'>
      <div className={buttonActive ? 'letstalk-layer layer-active' : 'letstalk-layer'}>
            <div className="board"></div>
            <div className="back-color"></div>
            <div className="parallax-container">
        {randomPositions.map((position, index) => (
         <IoMdArrowForward 
         key={index}
         className={`parallax-item item${index + 1}`}
         style={{
           transform: buttonActive ? `translate(${mousePosition.x / (index + 1)}px, ${mousePosition.y / (index + 1)}px)` : '',
           left: buttonActive ? `${position.left}px` : '',
           top: buttonActive ? `${position.top}px` : '',
         }}
         />

        ))}
      </div>
         </div>
      <div className="letstalk__container">
         
         <div className='letstalk__content'>
            <p className={!buttonActive ? "letstalk__subtitle" : "letstalk__subtitle layer-active"}>Hop On The Winning Team</p>
            <div className={!buttonActive ? "letstalk__title" : "letstalk__title layer-active"}>Hop On The Winning Team.</div>
            <Link
            onMouseMove={handleMouseMove}
            onMouseEnter={handleHover}
            onMouseLeave={handleButtonLeave} 
            className={buttonActive ? 'letstalk__link layer-active' : 'letstalk__link'} to=''>

               <span className='letstalk__link_text'>
               <WordShuffler
               buttonActive={buttonActive}
         text={shuffling ? "Let's talk" : "Let's talk "}
        textColor="#000"
        timeOffset={1}
        mixCapital={true}
        mixSpecialCharacters={true}
      />
               </span>
               <span className={buttonActive ? 'letstalk__link_layer layer-active' : 'letstalk__link_layer'}
                     style={{
                        left: ripplePosition.x + 'px',
                        top: ripplePosition.y + 'px',
                      }}
            ></span>

            </Link>
            <p className={!buttonActive ? "letstalk__text" : "letstalk__text layer-active"}>Let’s transform your vision into stunning reality. Reach out today and start the journey to a remarkable brand presence.</p>
        
         </div>
      </div>
    </section>
  )
}
